DROP TABLE IF EXISTS `StoryLocalization`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `StoryLocalization` (
  `id` int NOT NULL AUTO_INCREMENT,
  `storyId` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `lang` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `title` varchar(191) COLLATE utf8mb4_unicode_ci NOT NULL,
  `text` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `summary` text COLLATE utf8mb4_unicode_ci NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `StoryLocalization_storyId_lang_key` (`storyId`,`lang`),
  KEY `StoryLocalization_lang_idx` (`lang`),
  KEY `StoryLocalization_storyId_idx` (`storyId`),
  CONSTRAINT `StoryLocalization_storyId_fkey` FOREIGN KEY (`storyId`) REFERENCES `Story` (`id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=219 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

